class BookMyShow:

    def __init__(self, n: int, m: int):
        self.rows = [[m] for _ in range(n)]

    def gather(self, k: int, maxRow: int) -> List[int]:
        for i in range(min(maxRow + 1, len(self.rows))):
            if self.rows[i][0] >= k:
                self.rows[i][0] -= k
                return [i, m - self.rows[i][0]]
        return []

    def scatter(self, k: int, maxRow: int) -> bool:
        cnt = 0
        for i in range(min(maxRow + 1, len(self.rows))):
            cnt += self.rows[i][0]
            if cnt >= k:
                while k > 0:
                    for j in range(len(self.rows[i])):
                        if self.rows[i][j] > 0:
                            self.rows[i][j] -= 1
                            k -= 1
                            if k == 0:
                                return True
                return True
        return False
